using namespace std;

#define int long long

const int MOD = 1000000007;

// Function to multiply two 2x2 matrices
vector<vector<int>> matrixMultiply(vector<vector<int>>& A, vector<vector<int>>& B) {
    vector<vector<int>> C(2, vector<int>(2, 0));
    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 2; j++) {
            for (int k = 0; k < 2; k++) {
                C[i][j] += A[i][k]*B[k][j];
                C[i][j] %= MOD;
            }
        }
    }
    return C;
}

// Function to raise a matrix to the power n using binary exponentiation
vector<vector<int>> matrixPower(vector<vector<int>>& mat, int n) {
    if (n == 1) return mat;

    // Recursively compute half power
    vector<vector<int>> halfPower = matrixPower(mat, n / 2);

    // Square the result
    vector<vector<int>> result = matrixMultiply(halfPower, halfPower);

    // If n is odd, multiply one more time by the matrix
    if (n % 2 == 1) {
        result = matrixMultiply(result, mat);
    }

    return result;
}

