#include <stdio.h>
#include <stdlib.h>

#define MOD 1000000007

// Function to multiply two 2x2 matrices
void matrixMultiply(long int A[2][2], long int B[2][2], long int C[2][2]) {
    for (long int i = 0; i < 2; i++) {
        for (long int j = 0; j < 2; j++) {
            C[i][j] = 0;
            for (long int k = 0; k < 2; k++) {
                C[i][j] += A[i][k] * B[k][j];
                C[i][j] %= MOD;
            }
        }
    }
}

// Function to raise a matrix to the power n using binary exponentiation
void matrixPower(long int mat[2][2], long int n, long int result[2][2]) {
    if (n == 1) {
        result[0][0] = mat[0][0];
        result[0][1] = mat[0][1];
        result[1][0] = mat[1][0];
        result[1][1] = mat[1][1];
        return;
    }

    long int halfPower[2][2];
    matrixPower(mat, n / 2, halfPower);

    long int squared[2][2];
    matrixMultiply(halfPower, halfPower, squared);

    if (n % 2 == 1) {
        matrixMultiply(squared, mat, result);
    } else {
        result[0][0] = squared[0][0];
        result[0][1] = squared[0][1];
        result[1][0] = squared[1][0];
        result[1][1] = squared[1][1];
    }
}

// Function to solve each test case
void solveTestCase() {
    long int N;
    scanf("%ld", &N);

    // Base transformation matrix for Fibonacci sequence
    long int baseMatrix[2][2] = {{1, 1}, {1, 0}};

    long int resultMatrix[2][2];

    // Compute the (N-1)th power of the base matrix
    matrixPower(baseMatrix, N, resultMatrix);

    // The number of ways to tile an Nx2 grid is the top-left element of the result matrix
    printf("%ld\n", resultMatrix[0][0]);
}

int main() {
    long int T;  // Number of test cases
    scanf("%ld", &T);

    // Solve each test case
    for (long int t = 0; t < T; t++) {
        solveTestCase();
    }

    return 0;
}

