import java.util.*;
import java.lang.*;
import java.io.*;

import java.util.*;

class Codechef {

    // Constant for MOD value
    private static final long MOD = 1000000007;

    // Function to multiply two 2x2 matrices
    public static long[][] matrixMultiply(long[][] A, long[][] B) {
        long[][] C = new long[2][2];
        for (int i = 0; i < 2; i++) {
            for (int j = 0; j < 2; j++) {
                for (int k = 0; k < 2; k++) {
                    C[i][j] += A[i][k] * B[k][j];
                    C[i][j] %= MOD;  // Taking mod for each operation
                }
            }
        }
        return C;
    }

    // Function to raise a matrix to the power n using binary exponentiation
    public static long[][] matrixPower(long[][] mat, long n) {
        if (n == 1) {
            return mat;
        }

        // Recursively compute half power
        long[][] halfPower = matrixPower(mat, n / 2);

        // Square the result
        long[][] result = matrixMultiply(halfPower, halfPower);

        // If n is odd, multiply one more time by the matrix
        if (n % 2 == 1) {
            result = matrixMultiply(result, mat);
        }

        return result;
    }

    // Function to solve each test case
    public static void solveTestCase(Scanner sc) {
        long N = sc.nextLong();

        // Base transformation matrix for Fibonacci sequence
        long[][] baseMatrix = {{1, 1}, {1, 0}};

        // Compute the (N-1)th power of the base matrix
        long[][] resultMatrix = matrixPower(baseMatrix, N);

        // The number of ways to tile an Nx2 grid is the top-left element of the result matrix
        System.out.println(resultMatrix[0][0]);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();  // Number of test cases

        // Solve each test case
        for (int t = 0; t < T; t++) {
            solveTestCase(sc);
        }
    }
}
